mapper.select:
SELECT * FROM category
WHERE user_id IS NULL OR user_id = #{userId}
ORDER BY type ASC, sort_order ASC, create_time DESC

mapper.update:
UPDATE category
name = #{name}, type = #{type}, icon = #{icon}, color = #{color}, sort_order = #{sortOrder},
WHERE id = #{id}

mapper.select:
SELECT COUNT(*) FROM category
WHERE name = #{name}
AND (user_id IS NULL OR user_id = #{userId})
